def off_tumor_risk(tpm: dict, antigen: str, threshold=5.0):
    """Return tissues where antigen TPM exceeds threshold."""
    return sorted([t for t, v in tpm.items() if v >= threshold])

expr = {'tumor': 80, 'heart': 0.2, 'lung': 6.5, 'liver': 1.1}
print(off_tumor_risk(expr, 'TAA'))

def average_dar(species_fractions: dict) -> float:
    """species_fractions maps DAR->fraction (must sum ~1)."""
    return sum(dar * frac for dar, frac in species_fractions.items())

print(round(average_dar({0: 0.05, 2: 0.35, 4: 0.45, 6: 0.15}), 2))

import math

def ic50_nM_to_pic50(ic50_nM: float) -> float:
    return -math.log10(ic50_nM * 1e-9)

print(round(ic50_nM_to_pic50(100), 1))

def gc_fraction(seq: str) -> float:
    s = seq.upper()
    return (s.count('G') + s.count('C')) / max(len(s), 1)

print(round(gc_fraction('GCGCATAT'), 2))
